SELECT MIN(word_length) AS Minimum_Word_Length, AVG(frequency) AS Average_Word_Frequency
FROM words
WHERE part_of_speech = 'Noun';

SELECT COUNT(DISTINCT error_types.error_type)
FROM error_logs
JOIN error_types ON error_logs.error_id = error_types.error_id;

SELECT word
FROM words
WHERE word_id NOT IN (
  SELECT word_id 
  FROM corrections
);

SELECT 
  (SELECT report_id FROM reports WHERE user_id = 
    (SELECT user_id FROM reports ORDER BY error_rate DESC LIMIT 1)
  ) AS report_id,
  (SELECT COUNT(*) FROM error_logs WHERE user_id = 
    (SELECT user_id FROM reports ORDER BY error_rate DESC LIMIT 1)
  ) AS error_count;

SELECT difficulty_level
FROM educational_tools
WHERE tool_name = 'Error Correction Tool';

SELECT AVG(T1.age) AS average_age
FROM user_profiles AS T1
JOIN error_logs AS T2 ON T1.user_id = T2.user_id;

SELECT word, root, frequency
FROM words
WHERE frequency < (SELECT AVG(frequency) FROM words);

SELECT username, role
FROM user_profiles
WHERE age < (SELECT AVG(age) FROM user_profiles);

SELECT tool_id, duration, score
FROM learning_sessions
WHERE user_id = 1 OR tool_id = 0;

SELECT tool_id, progress
FROM learning_paths
WHERE completed = 1;

SELECT word, part_of_speech
FROM words
WHERE is_error = 1 AND LENGTH(root) > 10;

SELECT user_profiles.username, user_profiles.email
FROM user_profiles
WHERE user_profiles.age > (SELECT AVG(age) FROM user_profiles);

SELECT w.word, w.part_of_speech, w.frequency 
FROM words w
WHERE w.is_error = 1 AND w.frequency >= (SELECT AVG(w2.frequency) FROM words w2);

SELECT DISTINCT user_id 
FROM feedback 
WHERE tool_id = (SELECT tool_id FROM educational_tools WHERE tool_name = 'Error Correction Tool');

SELECT user_id
FROM learning_paths
WHERE last_accessed = (
    SELECT MAX(last_accessed)
    FROM learning_paths
);

SELECT up.username, el.context, el.error_id
FROM user_profiles up
JOIN error_logs el ON up.user_id = el.user_id;

SELECT tool_name
FROM educational_tools
WHERE tool_id = 0;
